insert into user_table( id, login_act, pass_word, nick_name, state, image_url, phone, open_id, last_time )
value ( #{id}, #{loginAct}, #{passWord}, #{nickName}, #{state}, #{imageUrl}, #{phone}, #{openId}, #{lastTime}
)

mapper.select:
SELECT
rc_learn.invitation_table.id, rc_learn.invitation_table.creat_time as createTime, rc_learn.invitation_table.coverImgUrl as imgUrl , rc_learn.invitation_table.title, rc_learn.invitation_table.type as label , rc_personal.user_table.image_url as userImgUrl, rc_personal.user_table.nick_name as userName
FROM rc_learn.invitation_table JOIN rc_personal.user_table ON rc_personal.user_table.id = rc_learn.invitation_table.userId where rc_learn.invitation_table.userId = #{currentUserId}

SELECT id, content, userId, parentId, likenumber, visitnumber, commentnumber, create_time, state
FROM rc_comment.discuss_comment_table
WHERE userId = #{currentUserId}
